3_real_world_example.code:
function greet(name) {
  return `Hello, ${name}!`;
}

function start() {
  const msg = greet('SkillSprint'); // greet() pushed, then popped
  console.log(msg);
}

start();
// Call Stack sequence:
// 1. [Global]
// 2. [Global] → [start]
// 3. [Global] → [start] → [greet]
// 4. [Global] → [start]   (greet returned)
// 5. [Global]             (start returned)

6_edge_case.code:
function infiniteLoop() {
  return infiniteLoop(); // pushes itself forever
}

try {
  infiniteLoop();
} catch (err) {
  console.log(err.message); // RangeError: Maximum call stack size exceeded
}
